SELECT dual_canonical.grouping_id, dual_canonical.event_month, dual_canonical.lag_day, dual_canonical.delta_day, dual_canonical.row_count, dual_canonical.n_source_eligible, dual_canonical.n_null_event_time, dual_canonical.n_null_source_only, dual_canonical.n_negative_clipped, dual_canonical.n_negative_lag_excluded, dual_canonical.n_overflow, dual_canonical.n_delta_rows, dual_canonical.max_lookup_dup, dual_canonical.n_staged_rows 
FROM (SELECT grouping(mp_dual.event_month) * $1 + grouping(mp_dual.lag_day) * $2 + grouping(mp_dual.delta_day) * $3 AS grouping_id, mp_dual.event_month AS event_month, mp_dual.lag_day AS lag_day, mp_dual.delta_day AS delta_day, coalesce(sum(mp_dual.is_probe_row), $4) AS row_count, coalesce(sum(mp_dual.is_source_eligible), $5) AS n_source_eligible, coalesce(sum(mp_dual.is_null_event_time), $6) AS n_null_event_time, coalesce(sum(mp_dual.is_null_source_only), $7) AS n_null_source_only, coalesce(sum(mp_dual.is_negative_clipped), $8) AS n_negative_clipped, coalesce(sum(mp_dual.is_negative_lag_excluded), $9) AS n_negative_lag_excluded, coalesce(sum(mp_dual.is_overflow), $10) AS n_overflow, coalesce(sum(mp_dual.is_delta_row), $11) AS n_delta_rows, max(mp_dual.lookup_dup) AS max_lookup_dup, count(*) AS n_staged_rows 
FROM mp_dual GROUP BY GROUPING SETS ((mp_dual.event_month, mp_dual.lag_day), (mp_dual.delta_day)) 
HAVING coalesce(sum(mp_dual.is_probe_row), $12) > $13 UNION ALL SELECT $14 AS grouping_id, CAST(NULL AS DATE) AS event_month, CAST(NULL AS INTEGER) AS lag_day, CAST(NULL AS INTEGER) AS delta_day, coalesce(sum(mp_dual.is_probe_row), $15) AS row_count, coalesce(sum(mp_dual.is_source_eligible), $16) AS n_source_eligible, coalesce(sum(mp_dual.is_null_event_time), $17) AS n_null_event_time, coalesce(sum(mp_dual.is_null_source_only), $18) AS n_null_source_only, coalesce(sum(mp_dual.is_negative_clipped), $19) AS n_negative_clipped, coalesce(sum(mp_dual.is_negative_lag_excluded), $20) AS n_negative_lag_excluded, coalesce(sum(mp_dual.is_overflow), $21) AS n_overflow, coalesce(sum(mp_dual.is_delta_row), $22) AS n_delta_rows, max(mp_dual.lookup_dup) AS max_lookup_dup, count(*) AS n_staged_rows 
FROM mp_dual) AS dual_canonical ORDER BY dual_canonical.grouping_id 
 LIMIT $23
